const incoming = $input.first().json;
const headers = incoming.headers || {};
const expectedKey = String($env.OMX_SHARED_KEY || $env.OMX_SOURCE_KEY || '').trim();
if (!expectedKey) {
  throw new Error('OMX_SHARED_KEY 가 설정되지 않았습니다.');
}
const providedKey = String(headers['x-omx-source-key'] || headers['X-Omx-Source-Key'] || '').trim();
if (providedKey !== expectedKey) {
  throw new Error('OMX shared key mismatch');
}
const payload = incoming.body && typeof incoming.body === 'object' ? incoming.body : incoming;
const baseUrl = String($env.NAVER_COMMERCE_API_BASE || 'https://api.commerce.naver.com/external').replace(/\/$/, '');
const mode = String(payload.mode || 'DRY_RUN').trim().toUpperCase();
const clientId = String($env.NAVER_COMMERCE_CLIENT_ID || '').trim();
const clientSecret = String($env.NAVER_COMMERCE_CLIENT_SECRET || '').trim();
const items = Array.isArray(payload.items) ? payload.items : [];
if (!items.length) {
  throw new Error('보낼 항목이 없습니다.');
}
const bcrypt = require('bcryptjs');
function toQueryString(params) {
  return Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null && String(value) !== '')
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
    .join('&');
}
const timestamp = String(Date.now());
let tokenForm = '';
if (mode === 'LIVE_SEND') {
  if (!clientId || !clientSecret) {
    throw new Error('NAVER_COMMERCE_CLIENT_ID / NAVER_COMMERCE_CLIENT_SECRET 이 설정되지 않았습니다.');
  }
  const password = `${clientId}_${timestamp}`;
  const clientSecretSign = Buffer.from(bcrypt.hashSync(password, clientSecret)).toString('base64');
  tokenForm = toQueryString({
    client_id: clientId,
    timestamp,
    client_secret_sign: clientSecretSign,
    grant_type: 'client_credentials',
    type: 'SELF',
  });
}
const out = items.map((raw) => {
  const sourceKind = String(raw.sourceKind || 'product_qna').trim();
  const rawId = String(raw.id || '').trim();
  const externalId = sourceKind === 'product_qna' ? rawId.replace(/^qna_/, '') : rawId;
  const reply = String(raw.reply || '').trim();
  if (!externalId) {
    throw new Error('external id가 비어 있습니다.');
  }
  if (!reply) {
    throw new Error(`reply_content_missing:${rawId}`);
  }
  const isCustomerInquiry = sourceKind === 'customer_inquiry';
  const requestUrl = isCustomerInquiry
    ? `${baseUrl}/v1/pay-merchant/inquiries/${externalId}/answer`
    : `${baseUrl}/v1/contents/qnas/${externalId}`;
  const requestBody = isCustomerInquiry
    ? { replyContent: reply }
    : { commentContent: reply };
  return {
    json: {
      original_id: rawId,
      external_id: externalId,
      source_kind: sourceKind,
      mode,
      should_send: mode === 'LIVE_SEND',
      token_url: `${baseUrl}/v1/oauth2/token`,
      token_form: tokenForm,
      request_url: requestUrl,
      request_method: isCustomerInquiry ? 'POST' : 'PUT',
      request_body: requestBody,
      item_type: raw.itemType || 'inquiry',
      product_name: raw.productName || '',
      customer_name: raw.customerName || '고객',
      title: raw.title || '문의',
    }
  };
});
return out;

const https = require('https');
const request = $('요청 payload 검증').first().json;
const tokenUrl = String(request.token_url || '').trim();
const tokenForm = String(request.token_form || '').trim();
if (!tokenUrl || !tokenForm) {
  throw new Error('스마트스토어 토큰 요청 정보가 비어 있습니다.');
}
async function postForm(urlString, body) {
  return await new Promise((resolve, reject) => {
    const req = https.request(urlString, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Accept: 'application/json',
        'Content-Length': String(Buffer.byteLength(body)),
      },
    }, (res) => {
      let text = '';
      res.setEncoding('utf8');
      res.on('data', (chunk) => {
        text += chunk;
      });
      res.on('end', () => {
        resolve({ statusCode: res.statusCode || 0, body: text });
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}
const response = await postForm(tokenUrl, tokenForm);
let body;
try {
  body = response.body ? JSON.parse(response.body) : {};
} catch (error) {
  body = { raw: response.body };
}
if (response.statusCode < 200 || response.statusCode >= 300 || !body.access_token) {
  throw new Error(`스마트스토어 토큰 발급 실패: ${response.statusCode} ${JSON.stringify(body)}`);
}
return [{ json: body }];

const original = $('요청 payload 검증').item.json;
return { result: {
  id: original.original_id,
  ok: true,
  message: 'DRY_RUN 완료',
  externalStatus: 'OPEN',
  statusCode: 200,
  dispatchMode: original.mode,
} };

const original = $('요청 payload 검증').item.json;
const body = $json || {};
const bodyText = typeof body === 'string' ? body : JSON.stringify(body);
const hasError = body && typeof body === 'object' && (body.code || body.error || body.message);
const ok = !hasError || bodyText === '{}' || bodyText === '';
const message = ok ? 'LIVE_SEND 완료' : String(body.message || body.error || body.code || 'send_failed');
return { result: {
  id: original.original_id,
  ok,
  message,
  externalStatus: ok ? 'ANSWERED' : 'OPEN',
  statusCode: ok ? 200 : 500,
  dispatchMode: original.mode,
} };

const results = $input.all().map((item) => item.json.result || item.json).filter(Boolean);
const dispatchMode = results[0] ? results[0].dispatchMode : 'UNKNOWN';
return [{ json: {
  results,
  meta: {
    channel: 'smartstore',
    mode: dispatchMode,
    totalCount: results.length,
  }
} }];
